describe('Ticket Status State Machine', () => {
  describe('Valid transitions', () => {
    it('Open → In Progress (200)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${OPEN_TICKET_ID}/status`)
        .send({ status: 'in_progress' });
