      const createRes = await request(app)
        .post('/api/tickets')
        .send({ title: 'Test invalid open to closed', description: 'Cannot skip resolved', priority: 'low', createdBy: VALID_USER_ID });
      const ticketId = createRes.body.data.id;
      const res = await request(app).patch(`/api/tickets/${ticketId}/status`).send({ status: 'closed' });
      expect(res.status).toBe(422);
    });

    it('Closed → any status is rejected (terminal state)', async () => {
      const res = await request(app).patch(`/api/tickets/${CLOSED_TICKET_ID}/status`).send({ status: 'open' });
      expect(res.status).toBe(422);
      expect(res.body.errors[0].message).toContain('terminal state');
    });

    it('Cancelled → any status is rejected (terminal state)', async () => {
      const res = await request(app).patch(`/api/tickets/${CANCELLED_TICKET_ID}/status`).send({ status: 'open' });
      expect(res.status).toBe(422);
      expect(res.body.errors[0].message).toContain('terminal state');
