#### 7. TicketListPage: inline arrow functions in table row `.map()` loop

**File:** [TicketListPage.tsx](frontend/src/pages/TicketListPage.tsx#L106-L118)

**Issue:** `onClick={() => navigate(...)}` and `onKeyDown={(e) => ...}` inside `.map()` create new function refs per row per render.

**Fix:** Extract a `TicketRow` component:
```tsx
const TicketRow: React.FC<{ ticket: Ticket; onNavigate: (id: string) => void }> = React.memo(
  ({ ticket, onNavigate }) => {
    const handleClick = useCallback(() => onNavigate(ticket.id), [ticket.id, onNavigate]);
    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent) => { if (e.key === 'Enter') onNavigate(ticket.id); },
      [ticket.id, onNavigate],
    );
    return (
      <tr onClick={handleClick} onKeyDown={handleKeyDown} className="ticket-list-page__row" role="link" tabIndex={0}>
        <td className="ticket-list-page__title-cell">{ticket.title}</td>
        <td><StatusBadge status={ticket.status} size="sm" /></td>
        <td><PriorityBadge priority={ticket.priority} size="sm" /></td>
        <td className="ticket-list-page__date">{new Date(ticket.createdAt).toLocaleDateString('en-AU')}</td>
      </tr>
    );
  },
);
```

