import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { pool } from '../config/database';
import { env } from '../config/env';
import { AuthUser, JwtPayload, UpdateProfileDto } from '../models/types';

export class AuthService {
  async login(email: string, password: string): Promise<{ token: string; user: AuthUser }> {
    const result = await pool.query(
      `SELECT u.id, u.name, u.email, r.name AS role, u.password_hash AS "passwordHash"
       FROM users u JOIN roles r ON r.id = u.role_id
       WHERE u.email = $1`,
      [email],
    );

    const user = result.rows[0];
    if (!user || !user.passwordHash) {
      throw { status: 401, errors: [{ message: 'Invalid email or password' }] };
    }

    const isValid = await bcrypt.compare(password, user.passwordHash);
    if (!isValid) {
      throw { status: 401, errors: [{ message: 'Invalid email or password' }] };
    }

    const payload: JwtPayload = {
      userId: user.id,
      email: user.email,
      role: user.role,
    };

    const token = jwt.sign(payload, env.jwtSecret, {
      expiresIn: env.jwtExpiresIn as string & jwt.SignOptions['expiresIn'],
    });

    return {
      token,
      user: { id: user.id, name: user.name, email: user.email, role: user.role },
    };
  }

  async getMe(userId: string): Promise<AuthUser> {
    const result = await pool.query(
      `SELECT u.id, u.name, u.email, r.name AS role
       FROM users u JOIN roles r ON r.id = u.role_id
       WHERE u.id = $1`,
      [userId],
    );

    if (!result.rows[0]) {
      throw { status: 404, errors: [{ message: 'User not found' }] };
    }

    return result.rows[0];
  }

  async updateProfile(userId: string, dto: UpdateProfileDto): Promise<AuthUser> {
    // If changing password, verify current password first
    if (dto.newPassword) {
      if (!dto.currentPassword) {
        throw { status: 400, errors: [{ message: 'Current password is required to change password', field: 'currentPassword' }] };
      }

      const result = await pool.query(
        `SELECT password_hash AS "passwordHash" FROM users WHERE id = $1`,
        [userId],
      );

      if (!result.rows[0]) {
        throw { status: 404, errors: [{ message: 'User not found' }] };
      }

      const isValid = await bcrypt.compare(dto.currentPassword, result.rows[0].passwordHash);
      if (!isValid) {
        throw { status: 400, errors: [{ message: 'Current password is incorrect', field: 'currentPassword' }] };
      }
    }

    const setClauses: string[] = [];
    const params: unknown[] = [];
    let paramIndex = 1;

    if (dto.name) {
      setClauses.push(`name = $${paramIndex++}`);
      params.push(dto.name);
    }

    if (dto.email) {
      // Check uniqueness
      const existing = await pool.query(
        `SELECT id FROM users WHERE email = $1 AND id != $2`,
        [dto.email, userId],
      );
      if (existing.rows.length > 0) {
        throw { status: 400, errors: [{ message: 'Email is already in use', field: 'email' }] };
      }
      setClauses.push(`email = $${paramIndex++}`);
      params.push(dto.email);
    }

    if (dto.newPassword) {
      const hash = await bcrypt.hash(dto.newPassword, 12);
      setClauses.push(`password_hash = $${paramIndex++}`);
      params.push(hash);
    }

    if (setClauses.length === 0) {
      return this.getMe(userId);
    }

    setClauses.push(`updated_at = NOW()`);
    params.push(userId);

    await pool.query(
      `UPDATE users SET ${setClauses.join(', ')}
       WHERE id = $${paramIndex}`,
      params,
    );

    return this.getMe(userId);
  }
}

