// so that bcrypt.compare takes equal time for existent and non-existent users.
private static readonly DUMMY_HASH = bcrypt.hashSync('dummy-timing-padding', 12);

async login(email: string, password: string): Promise<{ token: string; user: AuthUser }> {
  const user = await this.userRepository.findByEmailWithPassword(email);

  // Always run bcrypt.compare to prevent timing-based user enumeration
  const hashToCompare = user?.passwordHash || AuthService.DUMMY_HASH;
  const isValid = await bcrypt.compare(password, hashToCompare);

  if (!user || !user.passwordHash || !isValid) {
    throw new AppError(401, 'Invalid email or password');
  }

