import request from 'supertest';
import app from '../src/app';
import { USER_TOKEN, AGENT_TOKEN, TEST_USERS } from './helpers';

process.env.DB_NAME = 'ticket_management_test';

const VALID_USER_ID = TEST_USERS.user.userId;
const AGENT_USER_ID = TEST_USERS.agent.userId;

describe('Ticket CRUD', () => {
  describe('POST /api/tickets', () => {
    it('creates a ticket with valid data (201)', async () => {
      const res = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'New test ticket',
          description: 'A valid test ticket description',
          priority: 'medium',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(201);
      expect(res.body.data).toHaveProperty('id');
      expect(res.body.data.title).toBe('New test ticket');
      expect(res.body.data.status).toBe('open');
    });

    it('creates a ticket with assignee and prLink (201)', async () => {
      const res = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Ticket with assignee',
          description: 'Full details ticket',
          priority: 'high',
          assignedTo: AGENT_USER_ID,
          prLink: 'https://github.com/org/repo/pull/99',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(201);
      expect(res.body.data.assignedTo).toBe(AGENT_USER_ID);
      expect(res.body.data.prLink).toBe('https://github.com/org/repo/pull/99');
    });

    it('rejects ticket with missing title (422)', async () => {
      const res = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          description: 'No title provided',
          priority: 'low',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(422);
      expect(res.body.errors).toBeDefined();
      expect(res.body.errors.some((e: { field: string }) => e.field === 'title')).toBe(true);
    });

    it('rejects ticket with missing description (422)', async () => {
      const res = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Missing description',
          priority: 'low',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(422);
      expect(res.body.errors.some((e: { field: string }) => e.field === 'description')).toBe(true);
    });

    it('rejects ticket with invalid priority (422)', async () => {
      const res = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Invalid priority',
          description: 'Testing invalid enum',
          priority: 'urgent',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(422);
    });

    it('rejects unauthenticated request (401)', async () => {
      const res = await request(app)
        .post('/api/tickets')
        .send({
          title: 'No auth',
          description: 'Should fail',
          priority: 'low',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(401);
    });

    it('rejects agent creating ticket (403)', async () => {
      const res = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${AGENT_TOKEN}`)
        .send({
          title: 'Agent ticket',
          description: 'Agents are read-only',
          priority: 'low',
          createdBy: AGENT_USER_ID,
        });
      expect(res.status).toBe(403);
    });
  });

  describe('PATCH /api/tickets/:id', () => {
    let ticketId: string;

    beforeAll(async () => {
      const res = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Ticket to update',
          description: 'Will be updated',
          priority: 'low',
          createdBy: VALID_USER_ID,
        });
      ticketId = res.body.data.id;
    });

    it('updates title, description, priority (200)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${ticketId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Updated title',
          description: 'Updated description',
          priority: 'critical',
        });
      expect(res.status).toBe(200);
      expect(res.body.data.title).toBe('Updated title');
      expect(res.body.data.priority).toBe('critical');
    });

    it('updates assignedTo (200)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${ticketId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ assignedTo: AGENT_USER_ID });
      expect(res.status).toBe(200);
      expect(res.body.data.assignedTo).toBe(AGENT_USER_ID);
    });

    it('updates prLink (200)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${ticketId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ prLink: 'https://github.com/org/repo/pull/100' });
      expect(res.status).toBe(200);
      expect(res.body.data.prLink).toBe('https://github.com/org/repo/pull/100');
    });

    it('rejects update with invalid priority (422)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${ticketId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ priority: 'super_high' });
      expect(res.status).toBe(422);
    });

    it('returns 404 for non-existent ticket', async () => {
      const res = await request(app)
        .patch('/api/tickets/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ title: 'Ghost ticket' });
      expect(res.status).toBe(404);
    });
  });

  describe('GET /api/tickets', () => {
    it('returns paginated list of tickets', async () => {
      const res = await request(app)
        .get('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data).toBeInstanceOf(Array);
      expect(res.body).toHaveProperty('total');
      expect(res.body).toHaveProperty('page');
      expect(res.body).toHaveProperty('totalPages');
    });

    it('filters by status', async () => {
      const res = await request(app)
        .get('/api/tickets?status=open')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      res.body.data.forEach((ticket: { status: string }) => {
        expect(ticket.status).toBe('open');
      });
    });

    it('searches by keyword', async () => {
      const res = await request(app)
        .get('/api/tickets?search=Safari')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data.length).toBeGreaterThan(0);
    });

    it('rejects invalid status filter (422)', async () => {
      const res = await request(app)
        .get('/api/tickets?status=invalid')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(422);
    });

    it('rejects invalid priority filter (422)', async () => {
      const res = await request(app)
        .get('/api/tickets?priority=invalid')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(422);
    });
  });

  describe('GET /api/tickets/:id', () => {
    it('returns ticket details (200)', async () => {
      const res = await request(app)
        .get('/api/tickets/11111111-1111-1111-1111-111111111111')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data).toHaveProperty('title');
      expect(res.body.data).toHaveProperty('status');
    });

    it('returns 404 for non-existent ticket', async () => {
      const res = await request(app)
        .get('/api/tickets/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(404);
    });
  });
});

import request from 'supertest';
import app from '../src/app';
import { USER_TOKEN, TEST_USERS } from './helpers';

process.env.DB_NAME = 'ticket_management_test';

const VALID_USER_ID = TEST_USERS.user.userId;
const EXISTING_TICKET_ID = '11111111-1111-1111-1111-111111111111';
const NON_EXISTENT_TICKET_ID = '00000000-0000-0000-0000-000000000000';

describe('Comments', () => {
  describe('POST /api/tickets/:id/comments', () => {
    it('adds a comment to existing ticket (201)', async () => {
      const res = await request(app)
        .post(`/api/tickets/${EXISTING_TICKET_ID}/comments`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          message: 'This is a test comment',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(201);
      expect(res.body.data).toHaveProperty('id');
      expect(res.body.data.message).toBe('This is a test comment');
      expect(res.body.data.ticketId).toBe(EXISTING_TICKET_ID);
    });

    it('rejects comment with empty message (422)', async () => {
      const res = await request(app)
        .post(`/api/tickets/${EXISTING_TICKET_ID}/comments`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          message: '',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(422);
      expect(res.body.errors).toBeDefined();
    });

    it('returns 404 for non-existent ticket', async () => {
      const res = await request(app)
        .post(`/api/tickets/${NON_EXISTENT_TICKET_ID}/comments`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          message: 'Comment on ghost ticket',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(404);
    });

    it('rejects unauthenticated request (401)', async () => {
      const res = await request(app)
        .post(`/api/tickets/${EXISTING_TICKET_ID}/comments`)
        .send({
          message: 'No auth comment',
          createdBy: VALID_USER_ID,
        });
      expect(res.status).toBe(401);
    });
  });

  describe('GET /api/tickets/:id/comments', () => {
    it('returns comments for a ticket', async () => {
      const res = await request(app)
        .get(`/api/tickets/${EXISTING_TICKET_ID}/comments`)
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data).toBeInstanceOf(Array);
      expect(res.body.data.length).toBeGreaterThan(0);
      expect(res.body.data[0]).toHaveProperty('message');
      expect(res.body.data[0]).toHaveProperty('createdBy');
    });

    it('returns 404 for non-existent ticket', async () => {
      const res = await request(app)
        .get(`/api/tickets/${NON_EXISTENT_TICKET_ID}/comments`)
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(404);
    });
  });
});

import request from 'supertest';
import app from '../src/app';
import { USER_TOKEN, TEST_USERS } from './helpers';

process.env.DB_NAME = 'ticket_management_test';

const VALID_USER_ID = TEST_USERS.user.userId;
const OPEN_TICKET_ID = '22222222-2222-2222-2222-222222222222';
const IN_PROGRESS_TICKET_ID = '11111111-1111-1111-1111-111111111111';
const RESOLVED_TICKET_ID = '44444444-4444-4444-4444-444444444444';
const CLOSED_TICKET_ID = '55555555-5555-5555-5555-555555555555';
const CANCELLED_TICKET_ID = '66666666-6666-6666-6666-666666666666';

describe('Ticket Status State Machine', () => {
  describe('Valid transitions', () => {
    it('Open → In Progress (200)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${OPEN_TICKET_ID}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'in_progress' });
      expect(res.status).toBe(200);
      expect(res.body.data.status).toBe('in_progress');
    });

    it('In Progress → Resolved (200)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${IN_PROGRESS_TICKET_ID}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'resolved' });
      expect(res.status).toBe(200);
      expect(res.body.data.status).toBe('resolved');
    });

    it('Resolved → Closed (200)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${RESOLVED_TICKET_ID}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'closed' });
      expect(res.status).toBe(200);
      expect(res.body.data.status).toBe('closed');
    });

    it('Open → Cancelled (200)', async () => {
      const createRes = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Test cancellation from open',
          description: 'This ticket will be cancelled',
          priority: 'low',
          createdBy: VALID_USER_ID,
        });
      const ticketId = createRes.body.data.id;

      const res = await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'cancelled' });
      expect(res.status).toBe(200);
      expect(res.body.data.status).toBe('cancelled');
    });

    it('In Progress → Cancelled (200)', async () => {
      const createRes = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Test cancellation from in_progress',
          description: 'This ticket will be cancelled from in_progress',
          priority: 'medium',
          createdBy: VALID_USER_ID,
        });
      const ticketId = createRes.body.data.id;

      await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'in_progress' });

      const res = await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'cancelled' });
      expect(res.status).toBe(200);
      expect(res.body.data.status).toBe('cancelled');
    });
  });

  describe('Invalid transitions', () => {
    it('Open → Resolved is rejected (422)', async () => {
      const createRes = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Test invalid transition',
          description: 'Open cannot go directly to resolved',
          priority: 'low',
          createdBy: VALID_USER_ID,
        });
      const ticketId = createRes.body.data.id;

      const res = await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'resolved' });
      expect(res.status).toBe(422);
      expect(res.body.errors[0].message).toContain('Invalid status transition');
    });

    it('Open → Closed is rejected (422)', async () => {
      const createRes = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Test invalid open to closed',
          description: 'Cannot skip resolved',
          priority: 'low',
          createdBy: VALID_USER_ID,
        });
      const ticketId = createRes.body.data.id;

      const res = await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'closed' });
      expect(res.status).toBe(422);
    });

    it('Closed → any status is rejected (terminal state)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${CLOSED_TICKET_ID}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'open' });
      expect(res.status).toBe(422);
      expect(res.body.errors[0].message).toContain('terminal state');
    });

    it('Cancelled → any status is rejected (terminal state)', async () => {
      const res = await request(app)
        .patch(`/api/tickets/${CANCELLED_TICKET_ID}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'open' });
      expect(res.status).toBe(422);
      expect(res.body.errors[0].message).toContain('terminal state');
    });

    it('Resolved → In Progress is rejected (422)', async () => {
      const createRes = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Test resolved regression',
          description: 'Resolved cannot go back to in_progress',
          priority: 'medium',
          createdBy: VALID_USER_ID,
        });
      const ticketId = createRes.body.data.id;

      await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'in_progress' });
      await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'resolved' });

      const res = await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'in_progress' });
      expect(res.status).toBe(422);
    });
  });

  describe('Status persists in database', () => {
    it('Status is actually updated in DB after valid transition', async () => {
      const createRes = await request(app)
        .post('/api/tickets')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          title: 'Persistence test',
          description: 'Verify DB persistence',
          priority: 'high',
          createdBy: VALID_USER_ID,
        });
      const ticketId = createRes.body.data.id;

      await request(app)
        .patch(`/api/tickets/${ticketId}/status`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ status: 'in_progress' });

      const getRes = await request(app)
        .get(`/api/tickets/${ticketId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(getRes.body.data.status).toBe('in_progress');
    });
  });
});

import request from 'supertest';
import app from '../src/app';
import { ADMIN_TOKEN, USER_TOKEN, AGENT_TOKEN } from './helpers';

process.env.DB_NAME = 'ticket_management_test';

const DEFAULT_PERMISSIONS = {
  dashboard: { read: true, write: false },
  tickets: { read: true, write: false },
  kanban: { read: true, write: false },
  users: { read: false, write: false },
  roles: { read: false, write: false },
};

describe('Roles CRUD', () => {
  describe('GET /api/roles', () => {
    it('should return all roles for admin (200)', async () => {
      const res = await request(app)
        .get('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data).toBeInstanceOf(Array);
      expect(res.body.data.length).toBeGreaterThanOrEqual(3);
      expect(res.body.data[0]).toHaveProperty('id');
      expect(res.body.data[0]).toHaveProperty('name');
      expect(res.body.data[0]).toHaveProperty('permissions');
    });

    it('should reject non-admin user (403)', async () => {
      const res = await request(app)
        .get('/api/roles')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(403);
    });

    it('should reject agent (403)', async () => {
      const res = await request(app)
        .get('/api/roles')
        .set('Authorization', `Bearer ${AGENT_TOKEN}`);
      expect(res.status).toBe(403);
    });

    it('should reject unauthenticated request (401)', async () => {
      const res = await request(app).get('/api/roles');
      expect(res.status).toBe(401);
    });
  });

  describe('GET /api/roles/:id', () => {
    it('should return a role by ID (200)', async () => {
      // First get all roles to find an ID
      const listRes = await request(app)
        .get('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      const roleId = listRes.body.data[0].id;

      const res = await request(app)
        .get(`/api/roles/${roleId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data.id).toBe(roleId);
      expect(res.body.data).toHaveProperty('name');
      expect(res.body.data).toHaveProperty('permissions');
    });

    it('should return 404 for non-existent role', async () => {
      const res = await request(app)
        .get('/api/roles/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(404);
    });
  });

  describe('POST /api/roles', () => {
    it('should create a new role (201)', async () => {
      const res = await request(app)
        .post('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'test-role',
          description: 'A test role',
          permissions: DEFAULT_PERMISSIONS,
        });
      expect(res.status).toBe(201);
      expect(res.body.data).toHaveProperty('id');
      expect(res.body.data.name).toBe('test-role');
      expect(res.body.data.description).toBe('A test role');
      expect(res.body.data.permissions).toEqual(DEFAULT_PERMISSIONS);
    });

    it('should reject duplicate role name (400)', async () => {
      const res = await request(app)
        .post('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'admin',
          permissions: DEFAULT_PERMISSIONS,
        });
      expect(res.status).toBe(400);
      expect(res.body.errors[0].message).toContain('already exists');
    });

    it('should reject missing name (422)', async () => {
      const res = await request(app)
        .post('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          permissions: DEFAULT_PERMISSIONS,
        });
      expect(res.status).toBe(422);
    });

    it('should reject missing permissions (422)', async () => {
      const res = await request(app)
        .post('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'incomplete-role',
        });
      expect(res.status).toBe(422);
    });

    it('should reject non-admin user (403)', async () => {
      const res = await request(app)
        .post('/api/roles')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          name: 'user-created-role',
          permissions: DEFAULT_PERMISSIONS,
        });
      expect(res.status).toBe(403);
    });
  });

  describe('PATCH /api/roles/:id', () => {
    let testRoleId: string;

    beforeAll(async () => {
      const res = await request(app)
        .post('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'role-to-update',
          description: 'Will be updated',
          permissions: DEFAULT_PERMISSIONS,
        });
      testRoleId = res.body.data.id;
    });

    it('should update role name (200)', async () => {
      const res = await request(app)
        .patch(`/api/roles/${testRoleId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ name: 'updated-role-name' });
      expect(res.status).toBe(200);
      expect(res.body.data.name).toBe('updated-role-name');
    });

    it('should update role description (200)', async () => {
      const res = await request(app)
        .patch(`/api/roles/${testRoleId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ description: 'Updated description' });
      expect(res.status).toBe(200);
      expect(res.body.data.description).toBe('Updated description');
    });

    it('should update role permissions (200)', async () => {
      const newPerms = {
        ...DEFAULT_PERMISSIONS,
        tickets: { read: true, write: true },
      };
      const res = await request(app)
        .patch(`/api/roles/${testRoleId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ permissions: newPerms });
      expect(res.status).toBe(200);
      expect(res.body.data.permissions.tickets.write).toBe(true);
    });

    it('should reject duplicate name on update (400)', async () => {
      const res = await request(app)
        .patch(`/api/roles/${testRoleId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ name: 'admin' });
      expect(res.status).toBe(400);
    });

    it('should return 404 for non-existent role', async () => {
      const res = await request(app)
        .patch('/api/roles/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ name: 'ghost' });
      expect(res.status).toBe(404);
    });
  });

  describe('DELETE /api/roles/:id', () => {
    it('should delete a custom role with no users (204)', async () => {
      // Create a role to delete
      const createRes = await request(app)
        .post('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'role-to-delete',
          permissions: DEFAULT_PERMISSIONS,
        });
      const roleId = createRes.body.data.id;

      const res = await request(app)
        .delete(`/api/roles/${roleId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(204);

      // Verify it's gone
      const getRes = await request(app)
        .get(`/api/roles/${roleId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(getRes.status).toBe(404);
    });

    it('should reject deleting built-in role (400)', async () => {
      const listRes = await request(app)
        .get('/api/roles')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      const adminRole = listRes.body.data.find((r: { name: string }) => r.name === 'admin');

      const res = await request(app)
        .delete(`/api/roles/${adminRole.id}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(400);
      expect(res.body.errors[0].message).toContain('built-in');
    });

    it('should return 404 for non-existent role', async () => {
      const res = await request(app)
        .delete('/api/roles/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(404);
    });

    it('should reject non-admin user (403)', async () => {
      const res = await request(app)
        .delete('/api/roles/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(403);
    });
  });
});

import request from 'supertest';
import app from '../src/app';
import { ADMIN_TOKEN, USER_TOKEN, AGENT_TOKEN } from './helpers';

process.env.DB_NAME = 'ticket_management_test';

let adminRoleId: string;

describe('Users CRUD', () => {
  beforeAll(async () => {
    // Get the admin role ID for creating test users
    const rolesRes = await request(app)
      .get('/api/roles')
      .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
    adminRoleId = rolesRes.body.data.find((r: { name: string }) => r.name === 'user').id;
  });

  describe('GET /api/users', () => {
    it('should return all users for authenticated user (200)', async () => {
      const res = await request(app)
        .get('/api/users')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data).toBeInstanceOf(Array);
      expect(res.body.data.length).toBeGreaterThanOrEqual(5);
      expect(res.body.data[0]).toHaveProperty('id');
      expect(res.body.data[0]).toHaveProperty('name');
      expect(res.body.data[0]).toHaveProperty('email');
      expect(res.body.data[0]).toHaveProperty('role');
    });

    it('should not expose password hash in response', async () => {
      const res = await request(app)
        .get('/api/users')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      res.body.data.forEach((u: Record<string, unknown>) => {
        expect(u).not.toHaveProperty('passwordHash');
        expect(u).not.toHaveProperty('password_hash');
      });
    });

    it('should reject unauthenticated request (401)', async () => {
      const res = await request(app).get('/api/users');
      expect(res.status).toBe(401);
    });
  });

  describe('GET /api/users/:id', () => {
    it('should return a user by ID (200)', async () => {
      const listRes = await request(app)
        .get('/api/users')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      const userId = listRes.body.data[0].id;

      const res = await request(app)
        .get(`/api/users/${userId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(200);
      expect(res.body.data.id).toBe(userId);
    });

    it('should return 404 for non-existent user', async () => {
      const res = await request(app)
        .get('/api/users/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(404);
    });
  });

  describe('POST /api/users', () => {
    it('should create a new user as admin (201)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'Test User',
          email: 'testuser@example.com',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(201);
      expect(res.body.data).toHaveProperty('id');
      expect(res.body.data.name).toBe('Test User');
      expect(res.body.data.email).toBe('testuser@example.com');
      expect(res.body.data).not.toHaveProperty('passwordHash');
    });

    it('should reject duplicate email (400)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'Duplicate',
          email: 'alice@example.com',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(400);
      expect(res.body.errors[0].message).toContain('already in use');
    });

    it('should reject weak password (422)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'Weak Pass',
          email: 'weakpass@example.com',
          password: 'short',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(422);
    });

    it('should reject password without uppercase (422)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'No Upper',
          email: 'noupper@example.com',
          password: 'password1',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(422);
    });

    it('should reject password without digit (422)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'No Digit',
          email: 'nodigit@example.com',
          password: 'Password',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(422);
    });

    it('should reject missing name (422)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          email: 'noname@example.com',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(422);
    });

    it('should reject invalid email format (422)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'Bad Email',
          email: 'not-an-email',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(422);
    });

    it('should reject invalid roleId (422)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'Bad Role',
          email: 'badrole@example.com',
          password: 'Passw0rd!',
          roleId: 'not-a-uuid',
        });
      expect(res.status).toBe(422);
    });

    it('should reject non-admin user creating users (403)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({
          name: 'Unauthorized',
          email: 'unauth@example.com',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(403);
    });

    it('should reject agent creating users (403)', async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${AGENT_TOKEN}`)
        .send({
          name: 'Agent Create',
          email: 'agentcreate@example.com',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      expect(res.status).toBe(403);
    });
  });

  describe('PATCH /api/users/:id', () => {
    let testUserId: string;

    beforeAll(async () => {
      const res = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'User To Update',
          email: 'updateme@example.com',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      testUserId = res.body.data.id;
    });

    it('should update user name (200)', async () => {
      const res = await request(app)
        .patch(`/api/users/${testUserId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ name: 'Updated Name' });
      expect(res.status).toBe(200);
      expect(res.body.data.name).toBe('Updated Name');
    });

    it('should update user email (200)', async () => {
      const res = await request(app)
        .patch(`/api/users/${testUserId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ email: 'newemail@example.com' });
      expect(res.status).toBe(200);
      expect(res.body.data.email).toBe('newemail@example.com');
    });

    it('should reject duplicate email on update (400)', async () => {
      const res = await request(app)
        .patch(`/api/users/${testUserId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ email: 'alice@example.com' });
      expect(res.status).toBe(400);
    });

    it('should return 404 for non-existent user', async () => {
      const res = await request(app)
        .patch('/api/users/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({ name: 'Ghost' });
      expect(res.status).toBe(404);
    });

    it('should reject non-admin user updating (403)', async () => {
      const res = await request(app)
        .patch(`/api/users/${testUserId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`)
        .send({ name: 'Hacked' });
      expect(res.status).toBe(403);
    });
  });

  describe('DELETE /api/users/:id', () => {
    it('should delete a user with no tickets (204)', async () => {
      // Create a fresh user to delete
      const createRes = await request(app)
        .post('/api/users')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`)
        .send({
          name: 'Delete Me',
          email: 'deleteme@example.com',
          password: 'Passw0rd!',
          roleId: adminRoleId,
        });
      const userId = createRes.body.data.id;

      const res = await request(app)
        .delete(`/api/users/${userId}`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(204);

      // Verify deletion
      const getRes = await request(app)
        .get(`/api/users/${userId}`)
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(getRes.status).toBe(404);
    });

    it('should reject deleting user with tickets (400)', async () => {
      // Charlie (user) has created tickets in seed data
      const res = await request(app)
        .delete(`/api/users/c3d4e5f6-a7b8-9012-cdef-123456789012`)
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(400);
      expect(res.body.errors[0].message).toContain('ticket');
    });

    it('should return 404 for non-existent user', async () => {
      const res = await request(app)
        .delete('/api/users/00000000-0000-0000-0000-000000000000')
        .set('Authorization', `Bearer ${ADMIN_TOKEN}`);
      expect(res.status).toBe(404);
    });

    it('should reject non-admin user deleting (403)', async () => {
      const res = await request(app)
        .delete('/api/users/d4e5f6a7-b8c9-0123-def0-234567890123')
        .set('Authorization', `Bearer ${USER_TOKEN}`);
      expect(res.status).toBe(403);
    });
  });
});

